-- 4.5 Группа аналитической поддержки
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.5'
  FROM (VALUES
    ('Разработка новых и совершенствование действующих аналитических моделей, в том числе с использованием инструментов машинного обучения, применяемых Подразделением для выявления операций, подлежащих обязательному контролю, и подозрительных операций','analytical'),
    ('Проверка аналитических экспертных гипотез на больших объёмах данных по запросам работников Подразделения','analytical'),
    ('Разработка технических заданий для реализации Управлением систем комплаенс-контроля и управления рисками Департамента развития общебанковских систем по направлениям работы Подразделения, в части, касающейся деятельности Группы аналитической поддержки','methodology'),
    ('Использование возможности написания скриптов на языке программирования Python для анализа значительного объёма данных','analytical')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.5' AND u.is_archived = false;

-- 4.6 Центр оценки рисков государственного оборонного заказа
WITH ins2 AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.6'
  FROM (VALUES
    ('Обеспечение своевременного выявления, квалификации и формирования сообщений по подозрительным операциям (сделкам) с денежными средствами или иным имуществом, связанным с легализацией (отмыванием) доходов, полученных преступным путём, финансированием терроризма и финансированием распространения оружия массового уничтожения, клиентов ГОЗ','control'),
    ('Разработка программ и процедур, направленных на выявление и предотвращение подозрительных операций (сделок), совокупности подозрительных операций и (или) действий по отдельным счетам клиентов ГОЗ, которые могут привести к потере Банком деловой репутации или иным правовым и финансовым рискам, в части, касающейся деятельности Подразделения','methodology'),
    ('Выявление новых типов сомнительных финансовых схем по отдельным счетам клиентов ГОЗ, направленных на легализацию преступных доходов, финансирование терроризма или финансирование распространения оружия массового уничтожения','analytical'),
    ('Осуществление согласования платежей клиентов ГОЗ с признаками сомнительности','control'),
    ('Осуществление подготовки аналитических заключений по результатам оценки (анализа) операций (сделок) клиентов ГОЗ для Руководителя с целью их квалификации (обычные или подозрительные)','analytical'),
    ('Разработка технических заданий для реализации Управлением систем комплаенс-контроля и управления рисками Департамента развития общебанковских систем по вопросам, входящим в компетенцию Подразделения','methodology'),
    ('Осуществление рассмотрения обращений структурных бизнес-подразделений Банка по согласованию индивидуальных тарифов по клиентам ГОЗ в целях минимизации риска проведения такими клиентами подозрительных операций (сделок)','control'),
    ('Осуществление профилактики подозрительной активности в деятельности клиентов ГОЗ во взаимодействии со структурными бизнес-подразделениями Банка, обслуживающими клиентов ГОЗ','control'),
    ('Осуществление консультирования работников УФМ СЦ по вопросам формирования сообщений о подозрительных операциях в целях обеспечения неукоснительного соблюдения ими требований законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','communication'),
    ('Мониторинг и оценка рисков совершения сомнительных операций клиентами – участниками ГОЗ по операциям, совершаемым в Банке вне рамок исполнения ГОЗ, в том числе на основании сведений, полученных от Росфинмониторинга и других органов власти и уполномоченных органов','analytical'),
    ('Мониторинг и оценка рисков участников ГОЗ в рамках исполнения ГОЗ на основе сформированных риск-моделей поведенческой активности (типология совершения участниками ГОЗ сомнительных операций в сфере ГОЗ)','analytical'),
    ('Выявление сомнительных операций участников ГОЗ (в том числе типологий совершения сомнительных операций в сфере ГОЗ, полученных в рамках информационного обмена с Федеральной службой по финансовому мониторингу)','analytical'),
    ('Мониторинг и оценка рисков по совершению клиентом сомнительных операций в сфере ГОЗ с применением в аналитическом процессе сформированных типологий необычных операций, совершаемых в Банке, с учётом данных, полученных в рамках информационного обмена от Росфинмониторинга','analytical'),
    ('Формирование риск-профиля клиента Банка и выстраивание схемы его окружения, включая представителей клиента, выгодоприобретателей и бенефициарных владельцев, в целях оценки потенциального уровня риска совершаемых операций','analytical'),
    ('Построение риск-моделей поведенческой активности клиентов Банка в рамках исполнения ГОЗ','analytical'),
    ('Построение риск-моделей поведенческой активности клиентов Банка – участников ГОЗ в рамках осуществления хозяйственной деятельности, не связанной с ГОЗ','analytical'),
    ('Организация регулярной поддержки и эксплуатации внедрённых технологических решений аналитики финансового мониторинга рисков совершения сомнительных операций в сфере ГОЗ','operational'),
    ('Осуществление координации с уполномоченными органами государственной власти в целях формирования необходимых документов и материалов по мерам предупреждения рисков совершения сомнительных операций в сфере ГОЗ, включая подготовку ответов на полученные запросы от них','communication'),
    ('Осуществление коммуникаций и взаимодействий с федеральными органами исполнительной власти в рамках реагирования на риски совершения сомнительных операций в сфере ГОЗ','communication')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins2.id, u.id, 'owner', 'polozhenie'
FROM ins2 JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.6' AND u.is_archived = false;